 15→	"github.com/entireio/external-agents/e2e/agents"
 16→	"github.com/entireio/external-agents/e2e/entire"
 17→)
 18→
 19→// RepoState holds the working state for a single test's cloned repository.
 20→type RepoState struct {
 21→	Agent            agents.Agent
 22→	Dir              string
 23→	ArtifactDir      string
 24→	HeadBefore       string
 25→	CheckpointBefore string
 26→	ConsoleLog       *os.File
 27→	session          agents.Session // interactive session, if started via StartSession
 28→	skipArtifacts    bool           // suppresses artifact capture on scenario restart
 29→}
 30→
 31→// SetupRepo creates a fresh git repository in a temporary directory, seeds it
 32→// with an initial commit, and runs `entire enable` for the given agent.
 33→// Artifact capture is registered as a cleanup function.
 34→func SetupRepo(t *testing.T, agent agents.Agent) *RepoState {
 35→	t.Helper()
 36→
 37→	keepRepos := os.Getenv("E2E_KEEP_REPOS") != ""
 38→
 39→	dir, err := os.MkdirTemp("", "e2e-repo-*")
 40→	if err != nil {
 41→		t.Fatalf("create temp dir: %v", err)
 42→	}
 43→	if keepRepos {
 44→		t.Logf("E2E_KEEP_REPOS: repo will be preserved at %s", dir)
 45→	} else {
 46→		t.Cleanup(func() { os.RemoveAll(dir) })
 47→	}
 48→
 49→	// Resolve symlinks (macOS: /var -> /private/var) so paths match
 50→	// what agent CLIs see when they resolve their own CWD.
 51→	if resolved, err := filepath.EvalSymlinks(dir); err == nil {
 52→		dir = resolved
 53→	}
 54→
 55→	Git(t, dir, "init")
 56→	Git(t, dir, "config", "user.name", "E2E Test")
 57→	Git(t, dir, "config", "user.email", "e2e@test.local")
 58→	Git(t, dir, "commit", "--allow-empty", "-m", "initial commit")
 59→
 60→	// External agents need external_agents enabled in settings before enable.
 61→	if ea, ok := agent.(agents.ExternalAgent); ok && ea.IsExternalAgent() {
 62→		entireDir := filepath.Join(dir, ".entire")
 63→		if err := os.MkdirAll(entireDir, 0o755); err != nil {
 64→			t.Fatalf("create .entire for external agent: %v", err)
 65→		}
 66→		if err := os.WriteFile(filepath.Join(entireDir, "settings.json"),
 67→			[]byte("{\"external_agents\": true}\n"), 0o644); err != nil {
 68→			t.Fatalf("write external_agents setting: %v", err)
 69→		}
 70→	}
 71→
 72→	entire.Enable(t, dir, agent.EntireAgent())
 73→	PatchSettings(t, dir, map[string]any{"log_level": "debug"})
 74→
 75→	// Create artifact dir eagerly so console.log is written to disk
 76→	// incrementally. Even if the test is killed by a global timeout,
 77→	// partial output survives.
 78→	artDir := artifactDir(t)
 79→	consoleLog, err := os.Create(filepath.Join(artDir, "console.log"))
 80→	if err != nil {
 81→		t.Fatalf("create console.log: %v", err)
 82→	}
 83→
 84→	state := &RepoState{
 85→		Agent:            agent,
 86→		Dir:              dir,
 87→		ArtifactDir:      artDir,
 88→		HeadBefore:       GitOutput(t, dir, "rev-parse", "HEAD"),
 89→		CheckpointBefore: GitOutput(t, dir, "rev-parse", "entire/checkpoints/v1"),
 90→		ConsoleLog:       consoleLog,
 91→	}
 92→
 93→	t.Cleanup(func() {
 94→		_ = consoleLog.Close()
 95→		if !state.skipArtifacts {
 96→			CaptureArtifacts(t, state)
 97→		}
 98→	})
 99→
100→	return state
101→}
102→
103→// ForEachAgent runs fn as a parallel subtest for every registered agent.
104→// It handles repo setup, concurrency gating, context timeout, and cleanup.
105→// The timeout is scaled by each agent's TimeoutMultiplier.
106→func ForEachAgent(t *testing.T, timeout time.Duration, fn func(t *testing.T, s *RepoState, ctx context.Context)) {
107→	t.Helper()
108→	t.Parallel()
109→	all := agents.All()
110→	if len(all) == 0 {
111→		t.Skip("no agents registered (check E2E_AGENT filter)")
112→	}
113→	for _, agent := range all {
114→		t.Run(agent.Name(), func(t *testing.T) {
115→			t.Parallel()
116→			slotCtx := context.Background()
117→			if deadline, ok := t.Deadline(); ok {
118→				var cancel context.CancelFunc
119→				slotCtx, cancel = context.WithDeadline(slotCtx, deadline)
120→				defer cancel()
121→			}
122→			if err := agents.AcquireSlot(slotCtx, agent); err != nil {
123→				t.Fatalf("timed out waiting for agent slot: %v", err)
124→			}
125→			defer agents.ReleaseSlot(agent)
126→
127→			scaled := time.Duration(float64(timeout) * agent.TimeoutMultiplier())
128→
129→			var prevState *RepoState
130→			for attempt := range maxScenarioRestarts + 1 {
131→				s := SetupRepo(t, agent)
132→				ctx, cancel := context.WithTimeout(context.Background(), scaled)
133→
134→				if prevState != nil {
135→					prevState.skipArtifacts = true
136→				}
137→
138→				restarted := runScenario(t, s, ctx, fn)
139→				cancel()
140→
141→				if !restarted {
142→					return
143→				}
144→				prevState = s
145→				if attempt >= maxScenarioRestarts {
146→					t.Fatalf("exhausted %d scenario attempts due to transient API errors", maxScenarioRestarts+1)
147→				}
148→				t.Logf("transient error, restarting scenario (attempt %d/%d)", attempt+2, maxScenarioRestarts+1)
149→			}
150→		})
151→	}
152→}
153→
154→func runScenario(t *testing.T, s *RepoState, ctx context.Context, fn func(t *testing.T, s *RepoState, ctx context.Context)) (restarted bool) {
155→	t.Helper()
156→	defer func() {
157→		if r := recover(); r != nil {
158→			if _, ok := r.(errScenarioRestart); ok {
159→				restarted = true
160→				return
161→			}
162→			panic(r)
163→		}
164→	}()
165→	fn(t, s, ctx)
166→	return false
167→}
168→
169→const maxScenarioRestarts = 2
170→
171→type errScenarioRestart struct {
172→	msg string
173→}
174→
175→// RunPrompt runs an agent prompt, logs the command and output to ConsoleLog,
176→// and returns the result. If the agent reports a transient API error, it
177→// panics with errScenarioRestart to trigger a full scenario restart.
178→func (s *RepoState) RunPrompt(t *testing.T, ctx context.Context, prompt string, opts ...agents.Option) (agents.Output, error) {
179→	t.Helper()
180→	out, err := s.Agent.RunPrompt(ctx, s.Dir, prompt, opts...)
181→	s.logPromptResult(out)
182→
183→	if err != nil && s.Agent.IsTransientError(out, err) {
184→		errMsg := fmt.Sprintf("transient API error (stderr: %s)", strings.TrimSpace(out.Stderr))
185→		t.Logf("%s — restarting scenario", errMsg)
186→		fmt.Fprintf(s.ConsoleLog, "> [transient] %s — restarting scenario\n", errMsg)
187→		panic(errScenarioRestart{msg: errMsg})
188→	}
189→
190→	return out, err
191→}
192→
193→func (s *RepoState) logPromptResult(out agents.Output) {
194→	s.ConsoleLog.WriteString("> " + out.Command + "\n")
195→	s.ConsoleLog.WriteString("stdout:\n" + out.Stdout + "\n")
196→	s.ConsoleLog.WriteString("stderr:\n" + out.Stderr + "\n")
197→}
198→
199→// Git runs a git command in the repo and logs it to ConsoleLog.
200→func (s *RepoState) Git(t *testing.T, args ...string) {
201→	t.Helper()
202→	s.ConsoleLog.WriteString("> git " + strings.Join(args, " ") + "\n")
203→	Git(t, s.Dir, args...)
204→}
205→
206→// GitOutput runs a git command and returns its trimmed stdout.
207→func (s *RepoState) GitOutput(t *testing.T, args ...string) string {
208→	t.Helper()
209→	return GitOutput(t, s.Dir, args...)
210→}
211→
212→// StartSession starts an interactive session and registers it for pane
213→// capture in artifacts. Returns nil if the agent does not support interactive
214→// mode. The session is closed automatically during test cleanup.
215→func (s *RepoState) StartSession(t *testing.T, ctx context.Context) agents.Session {
216→	t.Helper()
217→	session, err := s.Agent.StartSession(ctx, s.Dir)
218→	if err != nil {
219→		t.Fatalf("start session: %v", err)
220→	}
221→	if session == nil {
222→		return nil
223→	}
224→	s.session = session
225→	return session
226→}
227→
228→// WaitFor waits for a pattern in the interactive session's pane and logs the
229→// pane content to ConsoleLog after the wait completes.
230→func (s *RepoState) WaitFor(t *testing.T, session agents.Session, pattern string, timeout time.Duration) {
231→	t.Helper()
232→	content, err := session.WaitFor(pattern, timeout)
233→	fmt.Fprintf(s.ConsoleLog, "> pane after WaitFor(%q):\n%s\n", pattern, content)
234→	if err != nil {
235→		t.Fatalf("WaitFor(%q): %v", pattern, err)
236→	}
237→}
238→
239→// IsExternalAgent returns true if the agent implements the ExternalAgent
240→// interface and reports itself as external.
241→func (s *RepoState) IsExternalAgent() bool {
242→	ea, ok := s.Agent.(agents.ExternalAgent)
243→	return ok && ea.IsExternalAgent()
244→}
245→
246→// Send sends input to an interactive session and logs it to ConsoleLog.
247→func (s *RepoState) Send(t *testing.T, session agents.Session, input string) {
248→	t.Helper()
249→	s.ConsoleLog.WriteString("> send: " + input + "\n")
250→	if err := session.Send(input); err != nil {
251→		t.Fatalf("send failed: %v", err)
252→	}
253→}
254→
255→// PatchSettings merges extra keys into .entire/settings.json.
256→func PatchSettings(t *testing.T, dir string, extra map[string]any) {
