 19→// DeepCheckpointValidation contains expected values for comprehensive checkpoint validation.
 20→type DeepCheckpointValidation struct {
 21→	CheckpointID              string
 22→	Strategy                  string
 23→	FilesTouched              []string
 24→	ExpectedPrompts           []string
 25→	ExpectedTranscriptContent []string
 26→}
 27→
 28→var hexIDPattern = regexp.MustCompile(`^[0-9a-f]{12}$`)
 29→
 30→// AssertFileExists asserts that at least one file matches the glob pattern
 31→// relative to dir.
 32→func AssertFileExists(t *testing.T, dir string, glob string) {
 33→	t.Helper()
 34→	matches, err := filepath.Glob(filepath.Join(dir, glob))
 35→	require.NoError(t, err)
 36→	assert.NotEmpty(t, matches, "expected files matching %s in %s", glob, dir)
 37→}
 38→
 39→// WaitForFileExists polls until at least one file matches the glob pattern
 40→// relative to dir, or fails the test after timeout.
 41→func WaitForFileExists(t *testing.T, dir string, glob string, timeout time.Duration) {
 42→	t.Helper()
 43→	pattern := filepath.Join(dir, glob)
 44→	deadline := time.Now().Add(timeout)
 45→	for {
 46→		matches, err := filepath.Glob(pattern)
 47→		require.NoError(t, err)
 48→		if len(matches) > 0 {
 49→			return
 50→		}
 51→		if time.Now().After(deadline) {
 52→			t.Fatalf("expected files matching %s in %s within %s", glob, dir, timeout)
 53→		}
 54→		time.Sleep(500 * time.Millisecond)
 55→	}
 56→}
 57→
 58→// AssertNewCommits polls until at least `atLeast` new commits exist since setup,
 59→// or fails after 20 seconds.
 60→func AssertNewCommits(t *testing.T, s *RepoState, atLeast int) {
 61→	t.Helper()
 62→	deadline := time.Now().Add(20 * time.Second)
 63→	for {
 64→		out := GitOutput(t, s.Dir, "log", "--oneline", s.HeadBefore+"..HEAD")
 65→		var lines []string
 66→		if out != "" {
 67→			lines = strings.Split(strings.TrimSpace(out), "\n")
 68→		}
 69→		if len(lines) >= atLeast {
 70→			return
 71→		}
 72→		if time.Now().After(deadline) {
 73→			t.Fatalf("expected at least %d new commit(s), got %d after 20s", atLeast, len(lines))
 74→		}
 75→		time.Sleep(500 * time.Millisecond)
 76→	}
