  3→package e2e
  4→
  5→import (
  6→	"encoding/json"
  7→	"fmt"
  8→	"os"
  9→	"os/exec"
 10→	"path/filepath"
 11→	"testing"
 12→)
 13→
 14→// TestEnv provides an isolated filesystem environment for E2E tests.
 15→type TestEnv struct {
 16→	t       *testing.T
 17→	Dir     string
 18→	HomeDir string
 19→	Runner  *AgentRunner
 20→}
 21→
 22→// NewTestEnv creates a bare test environment with ENTIRE_REPO_ROOT and isolated HOME.
 23→func NewTestEnv(t *testing.T, agentName string) *TestEnv {
 24→	t.Helper()
 25→
 26→	binPath, ok := AgentBinaries[agentName]
 27→	if !ok {
 28→		t.Fatalf("agent binary not found: %s (available: %v)", agentName, agentBinaryNames())
 29→	}
 30→
 31→	dir := t.TempDir()
 32→	homeDir := t.TempDir()
 33→
 34→	env := baseEnv(dir, homeDir)
 35→
 36→	return &TestEnv{
 37→		t:       t,
 38→		Dir:     dir,
 39→		HomeDir: homeDir,
 40→		Runner: &AgentRunner{
 41→			BinaryPath: binPath,
 42→			Env:        env,
 43→		},
 44→	}
 45→}
 46→
 47→// NewTestEnvWithBinary creates a test environment using an explicit binary path.
 48→// Use this from subpackages that build their own agent binary in TestMain.
 49→func NewTestEnvWithBinary(t *testing.T, binPath string) *TestEnv {
 50→	t.Helper()
 51→
 52→	dir := t.TempDir()
 53→	homeDir := t.TempDir()
 54→
 55→	env := baseEnv(dir, homeDir)
 56→
 57→	return &TestEnv{
 58→		t:       t,
 59→		Dir:     dir,
 60→		HomeDir: homeDir,
 61→		Runner: &AgentRunner{
 62→			BinaryPath: binPath,
 63→			Env:        env,
 64→		},
 65→	}
 66→}
 67→
 68→// NewKiroTestEnv creates a test environment with .kiro/ and .entire/tmp/ directories.
 69→func NewKiroTestEnv(t *testing.T) *TestEnv {
 70→	t.Helper()
 71→	te := NewTestEnv(t, "entire-agent-kiro")
 72→	te.MkdirAll(".kiro")
 73→	te.MkdirAll(".entire/tmp")
 74→	return te
 75→}
 76→
 77→// NewKiroGitEnv creates a Kiro test environment with git init.
 78→func NewKiroGitEnv(t *testing.T) *TestEnv {
 79→	t.Helper()
 80→	te := NewKiroTestEnv(t)
 81→	te.GitInit()
 82→	return te
 83→}
 84→
 85→// WriteFile writes content to a path relative to the test environment root.
 86→func (e *TestEnv) WriteFile(relPath, content string) {
 87→	e.t.Helper()
 88→	abs := filepath.Join(e.Dir, relPath)
 89→	if err := os.MkdirAll(filepath.Dir(abs), 0o750); err != nil {
 90→		e.t.Fatalf("mkdir for %s: %v", relPath, err)
 91→	}
 92→	if err := os.WriteFile(abs, []byte(content), 0o600); err != nil {
 93→		e.t.Fatalf("write %s: %v", relPath, err)
 94→	}
 95→}
 96→
 97→// WriteJSON writes a JSON-encoded value to a path relative to the test root.
 98→func (e *TestEnv) WriteJSON(relPath string, v any) {
 99→	e.t.Helper()
100→	data, err := json.Marshal(v)
101→	if err != nil {
102→		e.t.Fatalf("marshal JSON for %s: %v", relPath, err)
103→	}
104→	e.WriteFile(relPath, string(data))
105→}
106→
107→// ReadFile reads a file relative to the test environment root.
108→func (e *TestEnv) ReadFile(relPath string) string {
109→	e.t.Helper()
110→	data, err := os.ReadFile(filepath.Join(e.Dir, relPath))
111→	if err != nil {
112→		e.t.Fatalf("read %s: %v", relPath, err)
113→	}
114→	return string(data)
115→}
116→
117→// FileExists checks whether a relative path exists in the test environment.
118→func (e *TestEnv) FileExists(relPath string) bool {
119→	_, err := os.Stat(filepath.Join(e.Dir, relPath))
120→	return err == nil
121→}
122→
123→// MkdirAll creates a directory (and parents) relative to the test root.
124→func (e *TestEnv) MkdirAll(relPath string) {
125→	e.t.Helper()
126→	if err := os.MkdirAll(filepath.Join(e.Dir, relPath), 0o750); err != nil {
127→		e.t.Fatalf("mkdir %s: %v", relPath, err)
128→	}
129→}
130→
131→// GitInit initializes a git repo in the test environment root.
132→func (e *TestEnv) GitInit() {
133→	e.t.Helper()
134→	cmd := exec.Command("git", "init")
135→	cmd.Dir = e.Dir
136→	cmd.Env = e.Runner.Env
137→	if out, err := cmd.CombinedOutput(); err != nil {
138→		e.t.Fatalf("git init failed: %v\n%s", err, out)
139→	}
140→}
141→
142→// AbsPath returns the absolute path for a relative path in the test environment.
143→func (e *TestEnv) AbsPath(relPath string) string {
144→	return filepath.Join(e.Dir, relPath)
145→}
146→
147→func baseEnv(repoRoot, homeDir string) []string {
148→	return []string{
149→		fmt.Sprintf("ENTIRE_REPO_ROOT=%s", repoRoot),
150→		fmt.Sprintf("HOME=%s", homeDir),
151→		fmt.Sprintf("PATH=%s", os.Getenv("PATH")),
152→		"LANG=en_US.UTF-8",
153→	}
154→}
155→
156→func agentBinaryNames() []string {
157→	names := make([]string, 0, len(AgentBinaries))
158→	for name := range AgentBinaries {
159→		names = append(names, name)
160→	}
161→	return names
162→}
