func TestKiro_AreHooksInstalled_No(t *testing.T) {
	t.Parallel()
	env := NewKiroTestEnv(t)

	var resp struct {
		Installed bool `json:"installed"`
	}
	env.Runner.RunJSON(t, &resp, "", "are-hooks-installed")

	if resp.Installed {
		t.Error("hooks should not be installed in fresh env")
	}
