	t.Parallel()
	env := NewKiroTestEnv(t)

	var resp struct {
		Position int `json:"position"`
	}
	env.Runner.RunJSON(t, &resp, "", "get-transcript-position", "-path", env.AbsPath("nonexistent.json"))

